[asy]
pair A,B,C,N,K,M,J;
A=(0,5);
B=(12,0);
C=(0,0);
N=(5,0);
M=(0,4);
J=(0.35,4.84);
K=(6,2.4);
draw(A--B--C--cycle,linewidth(0.7));
draw(N--K,linewidth(0.7));
draw(M--J,linewidth(0.7));
label("$A$",A,NW);
label("$M$",M,W);
label("$C$",C,SW);
label("$N$",N,S);
label("$B$",B,SE);
label("$K$",K,NE);
label("$J$",J,NE);
[/asy]

